    51→        const id = `toast_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    52→        const newToast: Toast = { ...toast, id };
    53→        toastState!.toasts = [...toastState!.toasts, newToast];
    54→        notifyListeners();
    55→
    56→        // Auto remove after duration
