   138→      },
   139→      appearance: {
   140→        theme: 'system',
   141→        accentColor: 'blue',
   142→        language: 'it',
   143→      },
   144→      preferredProvider: 'auto',
   145→      preferredMicrophoneId: '', // Empty = system default
   146→      preferredOutputId: '', // Empty = system default (speakers)
   147→      preferredCameraId: '', // Empty = system default
   148→      // Voice settings defaults
