/**
 * Notification Triggers
 *
 * Wrapper functions to call from app code to trigger notifications.
 * The notificationService existed but was never wired up - these
 * functions bridge the gap.
 */

import { notificationService } from './notification-service';

/**
 * Call after session ends in conversation-flow.tsx
 */
export function onSessionComplete(params: {
  duration: number;
  xpEarned: number;
  subject?: string;
  maestroName?: string;
}): void {
  notificationService.sessionComplete(params.xpEarned, params.duration);
}

/**
 * Call in progress-store.ts when level increases
 */
export function onLevelUp(newLevel: number, title: string): void {
  notificationService.levelUp(newLevel, title);
}

/**
 * Call when achievement unlocked
 */
export function onAchievement(name: string, description: string): void {
  notificationService.achievement(name, description);
}

/**
 * Call when streak reaches milestones (3, 7, 14, 30, 50, 100, 365 days)
 */
export function onStreakMilestone(days: number): void {
  const milestones = [3, 7, 14, 30, 50, 100, 365];
  if (milestones.includes(days)) {
    notificationService.streakMilestone(days);
  }
}

/**
 * Call when streak is at risk (no activity today, near end of day)
 */
export function onStreakAtRisk(currentStreak: number): void {
  notificationService.streakAtRisk(currentStreak);
}

/**
 * Call when flashcards are due for review
 */
export function onFlashcardsDue(count: number): void {
  notificationService.flashcardReview(count);
}

/**
 * Call for study reminders
 */
export function onStudyReminder(subject?: string): void {
  notificationService.studyReminder(subject);
}

/**
 * Call for break reminders (ADHD mode)
 */
export function onBreakReminder(studyMinutes: number): void {
  notificationService.breakReminder(studyMinutes);
}

/**
 * Notification Service
 *
 * Provides high-level notification triggers for the application.
 * Uses the notification store for state management and delivery.
 */

import { useNotificationStore, requestPushPermission, isPushSupported } from '@/lib/stores/notification-store';
import type { NotificationType } from '@/lib/stores/notification-store';

export type { NotificationType };
export { requestPushPermission, isPushSupported };

// Re-export preferences type
export type { NotificationPreferences, Notification } from '@/lib/stores/notification-store';

/**
 * Notification triggers for common events
 */
export const notificationService = {
  /**
   * Send a notification
   */
  send: (params: {
    type: NotificationType;
    title: string;
    message: string;
    actionUrl?: string;
    metadata?: Record<string, unknown>;
  }): void => {
    useNotificationStore.getState().addNotification(params);
  },

  /**
   * Achievement unlocked
   */
  achievement: (name: string, description: string): void => {
    useNotificationStore.getState().addNotification({
      type: 'achievement',
      title: `Obiettivo sbloccato: ${name}`,
      message: description,
      actionUrl: '/progressi',
    });
  },

  /**
   * Streak milestone reached
   */
  streakMilestone: (days: number): void => {
    const messages: Record<number, string> = {
      3: 'Ottimo inizio! Continua così!',
      7: 'Una settimana intera! Sei fantastico!',
      14: 'Due settimane di studio! Incredibile!',
      30: 'Un mese di impegno costante! Sei un campione!',
      100: 'CENTO GIORNI! Sei una leggenda!',
    };

    const message = messages[days] || `${days} giorni consecutivi di studio!`;

    useNotificationStore.getState().addNotification({
      type: 'streak',
      title: `🔥 Streak: ${days} giorni!`,
      message,
      actionUrl: '/progressi',
    });
  },

  /**
   * Streak at risk warning
   */
  streakAtRisk: (currentStreak: number): void => {
    useNotificationStore.getState().addNotification({
      type: 'streak',
      title: 'La tua streak è a rischio!',
      message: `Hai una streak di ${currentStreak} giorni. Studia oggi per non perderla!`,
      actionUrl: '/maestri',
    });
  },

  /**
   * Study reminder
   */
  studyReminder: (subject?: string): void => {
    const title = subject
      ? `È ora di studiare ${subject}!`
      : 'È ora di studiare!';

    useNotificationStore.getState().addNotification({
      type: 'reminder',
      title,
      message: 'I tuoi Professori ti aspettano. Anche solo 15 minuti fanno la differenza!',
      actionUrl: '/maestri',
    });
  },

  /**
   * Flashcard review reminder
   */
  flashcardReview: (cardsCount: number): void => {
    useNotificationStore.getState().addNotification({
      type: 'reminder',
      title: 'Flashcard da ripassare',
      message: `Hai ${cardsCount} carte pronte per il ripasso. Il momento perfetto per consolidare!`,
      actionUrl: '/strumenti/flashcards',
    });
  },

  /**
   * Break reminder (ADHD mode)
   */
  breakReminder: (studyMinutes: number): void => {
    useNotificationStore.getState().addNotification({
      type: 'break',
      title: 'Tempo di una pausa!',
      message: `Hai studiato per ${studyMinutes} minuti. Fai una breve pausa per ricaricare le energie.`,
    });
  },

  /**
   * Session completed
   */
  sessionComplete: (xpEarned: number, minutesStudied: number): void => {
    useNotificationStore.getState().addNotification({
      type: 'session_end',
      title: 'Sessione completata!',
      message: `Hai guadagnato ${xpEarned} XP in ${minutesStudied} minuti di studio. Ottimo lavoro!`,
      actionUrl: '/progressi',
    });
  },

  /**
   * Level up
   */
  levelUp: (newLevel: number, newTitle: string): void => {
    useNotificationStore.getState().addNotification({
      type: 'level_up',
      title: `Livello ${newLevel} raggiunto!`,
      message: `Sei diventato "${newTitle}". Continua così per salire ancora!`,
      actionUrl: '/progressi',
    });
  },

  /**
